import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion('gpt-4', {
      apiKey: process.env.OPENAI_API_KEY,
    }),
  },
});

// Import code generation skills
const codeSkill = await kernel.importSkillFromDirectory("/path/to/code-skills");

// Create planner
const planner = kernel.createSequentialPlanner();

const plan = await planner.createPlan([
  `Generate Python function for: ${{user.input}}`,
  "Validate syntax",
  "Execute in sandbox",
  "Generate tests"
]);

async function runCodeAgent(prompt: string, kernel: Kernel) {
  let iteration = 0;
  let memory = [];

  while (iteration < 5) {
    const plan = await kernel.planner.createPlan([
      `Iteration ${iteration}: Generate code for: ${prompt}`,
      "Review memory: " + memory.slice(-3).join('\n'),
      "Execute and test previous code results"
    ]);

    const result = await kernel.runAsync(plan);
    memory.push(result.value);

    if (result.value.includes("ALL_TESTS_PASSED")) {
      return result.value;
    }

    iteration++;
  }
}

