import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: 'vex-your-key' });

// Vex verification middleware
const vexFilter = async (result: any, context: any): Promise<any> => {
  const checks = [
    'code_safety',
    'syntax_validity',
    'no_credential_leakage',
    'execution_sandboxing',
    'dependency_safety'
  ];

  const verdict = await vex.verify({
    input: result.toString(),
    context: { plugin: context.pluginName },
    policy: 'code-generation-high-risk',
    checks
  });

  if (!verdict.approved) {
    throw new Error(`Vex Safety Block: ${verdict.reason}`);
  }

  return result;
};

// Apply to kernel invocation
kernel.invocationContext.addPostHandler(vexFilter);
